import os
import json
from flask import Flask, request, jsonify
from datetime import datetime, timedelta

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(request):
    return f"{request.method}_{request.url}"

def load_from_cache(key):
    path = os.path.join(CACHE_DIR, key)
    if os.path.exists(path):
        with open(path, 'r') as file:
            data = json.load(file)
            return data.get('data'), datetime.fromisoformat(data['timestamp'])
    return None, None

def save_to_cache(key, data):
    path = os.path.join(CACHE_DIR, key)
    timestamp = datetime.now().isoformat()
    with open(path, 'w') as file:
        json.dump({'data': data, 'timestamp': timestamp}, file)

@app.route('/api', methods=['GET'])
def api():
    cache_key_value = cache_key(request)
    cached_data, cached_timestamp = load_from_cache(cache_key_value)
    
    if cached_data is not None and datetime.now() - cached_timestamp < timedelta(hours=1):
        return jsonify(cached_data), 200
    
    # Simulate expensive API call
    response_data = {
        'status': 'success',
        'data': {
            'items': [1, 2, 3],
            'metadata': {'count': 3}
        }
    }
    
    save_to_cache(cache_key_value, response_data)
    return jsonify(response_data), 200

if __name__ == '__main__':
    app.run(debug=True)